class CorporateActionTypeEnum(EnumDefinitionImpl):
    """
    The enumerated values to specify the origin of a corporate action transfer.
    """
    CashDividend = PermissibleValue(
        text="CashDividend",
        description="Corporate action triggered by the distribution of a cash dividend.")
    StockDividend = PermissibleValue(
        text="StockDividend",
        description="Corporate action triggered by the distribution of a stock dividend.")
    StockSplit = PermissibleValue(
        text="StockSplit",
        description="""Corporate action triggered by a stock split. A stock split or stock divide increases the number of shares in a public company. The price is adjusted such that the before and after market capitalization of the company remains the same and dilutiondoes not occur. The value maps closely to the ISO code (SPLF) defined as a distribution of subsidiary stock to the shareholders of the parent company without a surrender of shares.""")
    ReverseStockSplit = PermissibleValue(
        text="ReverseStockSplit",
        description="""Corporate action triggered by a reverse split. A reverse stock split or reverse split is a process by a company of issuing to each shareholder in that company a smaller number of new shares in proportion to that shareholder's original shares that are subsequently canceled. A reverse stock split is also called a stock merge. The reduction in the number of issued shares is accompanied by a proportional increase in the share price. The value maps closely to the ISO code (SPLR) defined as a decrease in a company's number of outstanding equities without any change in the shareholder's equity or the aggregate market value at the time of the split. Equity price and nominal value are increased accordingly.""")
    SpinOff = PermissibleValue(
        text="SpinOff",
        description="""Corporate action triggered by a spin Off. A spin-out, also known as a spin-off or a starburst, refers to a type of corporate action where a company splits off sections of itself as a separate business. The value maps closely to the ISO code (SOFF) defined as a a distribution of subsidiary stock to the shareholders of the parent company without a surrender of shares. Spin-off represents a form of divestiture usually resulting in an independent company or in an existing company. For example, demerger, distribution, unbundling.""")
    Merger = PermissibleValue(
        text="Merger",
        description="""Corporate action triggered by a merger. Mergers and acquisitions (abbreviated M&A) is an aspect of corporate strategy, corporate finance and management dealing with the buying, selling, dividing and combining of different companies and similar entities that can help an enterprise grow rapidly in its sector or location of origin, or a new field or new location, without creating a subsidiary, other child entity or using a joint venture. The distinction between a merger and an acquisition has become increasingly blurred in various respects (particularly in terms of the ultimate economic outcome), although it has not completely disappeared in all situations. The value maps closely to the ISO code (MRGR) defined as an offer made to shareholders, normally by a third party, requesting them to sell (tender) or exchange their equities.""")
    Delisting = PermissibleValue(
        text="Delisting",
        description="Corporate action triggered by the removal of a security from a stock exchange.")
    StockNameChange = PermissibleValue(
        text="StockNameChange",
        description="Corporate action triggered by a change in the name used to trade the security.")
    StockIdentifierChange = PermissibleValue(
        text="StockIdentifierChange",
        description="Corporate action triggered by a change in the code used to trade the security.")
    RightsIssue = PermissibleValue(
        text="RightsIssue",
        description="""Corporate action triggered by an issuance to shareholders of rights to purchase additional shares at a discount.""")
    Takeover = PermissibleValue(
        text="Takeover",
        description="""Corporate action triggered by a takeover. A takeover is the purchase of onecompany (the target) by another (the acquirer, or bidder). The value maps to the ISO code (TEND) but is finer grained than TEND which emcompasses Tender/Acquisition/Takeover/Purchase Offer/Buyback. ISO defines the TEND code as an offer made to shareholders, normally by a third party, requesting them to sell (tender) or exchange their equities.""")
    StockReclassification = PermissibleValue(
        text="StockReclassification",
        description="Corporate action triggered by a Stock Reclassification.")
    BonusIssue = PermissibleValue(
        text="BonusIssue",
        description="""Corporate action triggered by a bonus issue. A bonus issue or bonus share is a free share of stock given to current shareholders in a company, based upon the number of shares that the shareholder already owns. While the issue of bonus shares increases the total number of shares issued and owned, it does not change the value of the company. The value maps closely to the ISO code (BONU) defined as a bonus, scrip or capitalisation issue. Security holders receive additional assets free of payment from the issuer, in proportion to their holding.""")
    ClassAction = PermissibleValue(
        text="ClassAction",
        description="""Corporate action triggered by a Class Action. An action where an individual represents a group in a court claim. The judgment from the suit is for all the members of the group (class). The value maps closely to the ISO code (CLSA) defined as the situation where interested parties seek restitution for financial loss. The security holder may be offered the opportunity to join a class action proceeding and would need to respond with an instruction.""")
    EarlyRedemption = PermissibleValue(
        text="EarlyRedemption",
        description="""Corporate action triggered by an early redemption. The value maps closely to the ISO code (MCAL) defined as the redemption of an entire issue outstanding of securities, for example, bonds, preferred equity, funds, by the issuer or its agent, for example, asset manager, before final maturity.""")
    Liquidation = PermissibleValue(
        text="Liquidation",
        description="""Corporate action triggered by a liquidation. When a business or firm is terminated or bankrupt, its assets are sold (liquidated) and the proceeds pay creditors. Any leftovers are distributed to shareholders. The value maps closely to the ISO code (LIQU) defined as a distribution of cash, assets or both. Debt may be paid in order of priority based on preferred claims to assets specified by the security.""")
    BankruptcyOrInsolvency = PermissibleValue(
        text="BankruptcyOrInsolvency",
        description="""Corporate action triggered by bankruptcy, insolvency filing or insolvency of the issuer of the Security.""")
    IssuerNationalization = PermissibleValue(
        text="IssuerNationalization",
        description="Corporate action triggered by the nationalization of the issuer of the Security.")
    Relisting = PermissibleValue(
        text="Relisting",
        description="""Corporate action triggered by the relisting of a security from the original stock exchange to another exchange.""")
    BespokeEvent = PermissibleValue(
        text="BespokeEvent",
        description="""Corporate Action which is separately agreed between the parties and/or described elsewhere in the document (for instance in bespoke term described in string type objects present in some root attributes of Agreement type).""")

    _defn = EnumDefinition(
        name="CorporateActionTypeEnum",
        description="The enumerated values to specify the origin of a corporate action transfer.",
    )

class CreditEventTypeEnum(EnumDefinitionImpl):
    """
    Represents the enumerated values to specify a credit event type.
    """
    Bankruptcy = PermissibleValue(
        text="Bankruptcy",
        description="""The reference entity has been dissolved or has become insolvent. It also covers events that may be a precursor to insolvency such as instigation of bankruptcy or insolvency proceedings. Sovereign trades are not subject to Bankruptcy as 'technically' a Sovereign cannot become bankrupt. ISDA 2003 Term: Bankruptcy.""",
        meaning=FPML["credit-event-type-1-0#Bankruptcy"])
    DistressedRatingsDowngrade = PermissibleValue(
        text="DistressedRatingsDowngrade",
        description="""Results from the fact that the rating of the reference obligation is downgraded to a distressed rating level. From a usage standpoint, this credit event is typically not applicable in case of RMBS trades.""",
        meaning=FPML["credit-event-type-1-0#DistressedRatingsDowngrade"])
    FailureToPay = PermissibleValue(
        text="FailureToPay",
        description="""This credit event triggers, after the expiration of any applicable grace period, if the reference entity fails to make due payments in an aggregrate amount of not less than the payment requirement on one or more obligations (e.g. a missed coupon payment). ISDA 2003 Term: Failure to Pay.""",
        meaning=FPML["credit-event-type-1-0#FailureToPay"])
    FailureToPayInterest = PermissibleValue(
        text="FailureToPayInterest",
        description="""Corresponds to the failure by the Reference Entity to pay an expected interest amount or the payment of an actual interest amount that is less than the expected interest amount. ISDA 2003 Term: Failure to Pay Interest.""",
        meaning=FPML["credit-event-type-1-0#FailureToPayInterest"])
    FailureToPayPrincipal = PermissibleValue(
        text="FailureToPayPrincipal",
        description="""Corresponds to the failure by the Reference Entity to pay an expected principal amount or the payment of an actual principal amount that is less than the expected principal amount. ISDA 2003 Term: Failure to Pay Principal.""",
        meaning=FPML["credit-event-type-1-0#FailureToPayPrincipal"])
    GovernmentalIntervention = PermissibleValue(
        text="GovernmentalIntervention",
        description="""A governmental intervention is an event resulting from an action by a governmental authority that materially impacts the reference entity's obligations, such as an interest rate reduction, principal reduction, deferral of interest or principal, change in priority ranking, or change in currency or composition of payment. ISDA 2014 Term: Governmental Intervention.""",
        meaning=FPML["credit-event-type-1-0#GovernmentalIntervention"])
    ImpliedWritedown = PermissibleValue(
        text="ImpliedWritedown",
        description="""Results from the fact that losses occur to the underlying instruments that do not result in reductions of the outstanding principal of the reference obligation.""",
        meaning=FPML["credit-event-type-1-0#ImpliedWritedown"])
    MaturityExtension = PermissibleValue(
        text="MaturityExtension",
        description="Results from the fact that the underlier fails to make principal payments as expected.",
        meaning=FPML["credit-event-type-1-0#MaturityExtension"])
    ObligationAcceleration = PermissibleValue(
        text="ObligationAcceleration",
        description="""One or more of the obligations have been declared due and payable before they would otherwise have been due and payable as a result of, or on the basis of, the occurrence of a default, event of default or other similar condition or event other than failure to pay (preferred by the market over Obligation Default, because more definitive and encompasses the definition of Obligation Default - this is more favorable to the Seller). Subject to the default requirement amount. ISDA 2003 Term: Obligation Acceleration.""",
        meaning=FPML["credit-event-type-1-0#ObligationAcceleration"])
    ObligationDefault = PermissibleValue(
        text="ObligationDefault",
        description="""One or more of the obligations have become capable of being declared due and payable before they would otherwise have been due and payable as a result of, or on the basis of, the occurrence of a default, event of default or other similar condition or event other than failure to pay. ISDA 2003 Term: Obligation Default.""",
        meaning=FPML["credit-event-type-1-0#ObligationDefault"])
    RepudiationMoratorium = PermissibleValue(
        text="RepudiationMoratorium",
        description="""The reference entity, or a governmental authority, either refuses to recognise or challenges the validity of one or more obligations of the reference entity, or imposes a moratorium thereby postponing payments on one or more of the obligations of the reference entity. Subject to the default requirement amount. ISDA 2003 Term: Repudiation/Moratorium.""",
        meaning=FPML["credit-event-type-1-0#RepudiationMoratorium"])
    Restructuring = PermissibleValue(
        text="Restructuring",
        description="""A restructuring is an event that materially impacts the reference entity's obligations, such as an interest rate reduction, principal reduction, deferral of interest or principal, change in priority ranking, or change in currency or composition of payment. ISDA 2003 Term: Restructuring.""",
        meaning=FPML["credit-event-type-1-0#Restructuring"])
    Writedown = PermissibleValue(
        text="Writedown",
        description="Results from the fact that the underlier writes down its outstanding principal amount.",
        meaning=FPML["credit-event-type-1-0#Writedown"])

    _defn = EnumDefinition(
        name="CreditEventTypeEnum",
        description="Represents the enumerated values to specify a credit event type.",
    )

